refsection.programlisting:
image = im2double(rgb2gray(imread(fullpath(getIPCVpath() + "/images/opencv_fruits.jpg")));
volume = cat(3, image, image + 0.1, image + 0.2);
[labels, centers] = imsegkmeans3(volume, 3);
imshow(max(labels, 3));
disp(centers);

volume = zeros(40, 40, 6);
volume(5:20, 5:20, :) = 0.2;
volume(22:35, 22:35, :) = 0.8;
[labels, centers] = imsegkmeans3(volume, 2);
imshow(max(labels, 3));
